function collapseNavbar() {
    $(".navbar").offset().top > 50 ? $(".navbar-fixed-top, .socialTop, .btn-lg-out").addClass("top-nav-collapse") : $(".navbar-fixed-top, .socialTop, .btn-lg-out").removeClass("top-nav-collapse")
}

$(window).scroll(collapseNavbar), $(document).ready(collapseNavbar), $(function () {
    $("a.page-scroll").bind("click", function (e) {
        var t = $(this);
        $("html, body").stop().animate({
            scrollTop: $(t.attr("href")).offset().top
        }, 1500, "easeInOutExpo"), e.preventDefault()
    })
}), $(".navbar-collapse ul li a").click(function () {
    $(this).closest(".collapse").collapse("toggle")
});

